func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	assignOrder := make([]int, dispatch.AssignsLen)
	for i := range assignOrder {
		assignOrder[i] = i
	}
	rand.Shuffle(len(assignOrder), func(i, j int) {
		assignOrder[i], assignOrder[j] = assignOrder[j], assignOrder[i]
	})
	nextNewAssign := dispatch.AssignsLen
	insertedCount := 0
	for _, idx := range orderIndices {
		bestAssignIdx := -1
		bestCostDelta := math.MaxFloat64
		ori := oris[idx]
		des := dess[idx]
		shipID := total_ship + idx
		for _, aidx := range assignOrder {
			a := &dispatch.Assigns[aidx]
			oldCost := a.Cost
			ok := a.AddShip(shipID, ori, des)
			if ok {
				a.GenRoute()
				newCost := a.Cost
				if newCost >= 0 {
					costDelta := newCost - oldCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = aidx
					}
				}
			}
			if a.StationsLen == 0 || ok {
				a.RemoveShip(shipID)
				a.GenRoute()
			}
		}
		if bestAssignIdx != -1 {
			finalA := &dispatch.Assigns[bestAssignIdx]
			finalOk := finalA.AddShip(shipID, ori, des)
			if finalOk {
				finalA.GenRoute()
				insertedCount++
				continue
			}
		}
		fallbackSuccess := false
		for attempt := 0; attempt <= nextNewAssign-dispatch.AssignsLen; attempt++ {
			useIdx := dispatch.AssignsLen + attempt
			if useIdx >= MAXASSIGNS {
				break
			}
			a := &dispatch.Assigns[useIdx]
			if a.StationsLen > 0 {
				continue
			}
			ok := a.AddShip(shipID, ori, des)
			if ok {
				a.GenRoute()
				if a.Cost >= 0 {
					if useIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = useIdx + 1
					}
					fallbackSuccess = true
					insertedCount++
					break
				} else {
					a.RemoveShip(shipID)
					a.GenRoute()
				}
			}
		}
		if !fallbackSuccess && nextNewAssign < MAXASSIGNS {
			a := &dispatch.Assigns[nextNewAssign]
			ok := a.AddShip(shipID, ori, des)
			if ok {
				a.GenRoute()
				if a.Cost >= 0 {
					dispatch.AssignsLen = nextNewAssign + 1
					nextNewAssign++
					insertedCount++
				} else {
					a.RemoveShip(shipID)
					a.GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

